#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="D:\1PROGRAM\PROJ\portfolio\node_modules\.pnpm\vite-node@5.3.0_@types+node_0dda59107d775574562e483bb3de23d6\node_modules\vite-node\node_modules;D:\1PROGRAM\PROJ\portfolio\node_modules\.pnpm\vite-node@5.3.0_@types+node_0dda59107d775574562e483bb3de23d6\node_modules;D:\1PROGRAM\PROJ\portfolio\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/proc/cygdrive/d/1PROGRAM/PROJ/portfolio/node_modules/.pnpm/vite-node@5.3.0_@types+node_0dda59107d775574562e483bb3de23d6/node_modules/vite-node/node_modules:/proc/cygdrive/d/1PROGRAM/PROJ/portfolio/node_modules/.pnpm/vite-node@5.3.0_@types+node_0dda59107d775574562e483bb3de23d6/node_modules:/proc/cygdrive/d/1PROGRAM/PROJ/portfolio/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../vite-node/dist/cli.mjs" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../vite-node/dist/cli.mjs" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
